parameters.old_string:
/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications.
 * Currently focused on email settings — designed to extend
 * to additional channels in the future.
 */

import type { NotificationType } from './notification.js';

/**
 * How often a user wants to receive email notifications.
 * - instant: deliver immediately
 * - daily_digest: batch into a daily summary
 * - weekly_digest: batch into a weekly summary
 *
 * Note: only 'instant' is currently implemented. Digest modes
 * are modeled for forward-compatibility but not yet delivered.
 */
export type EmailFrequency = 'instant' | 'daily_digest' | 'weekly_digest';

/**
 * Per-category email subscription setting.
 */
export interface CategoryPreference {
  /** The notification category. */
  category: NotificationType;
  /** Whether the user wants to receive this category. */
  enabled: boolean;
}

/**
 * Full notification preferences for a single user.
 */
export interface UserPreferences {
  /** Unique preferences record ID. */
  id: string;
  /** The user this preferences record belongs to. */
  userId: string;
  /** Master switch for all email notifications. */
  emailEnabled: boolean;
  /** How often to deliver email notifications. */
  emailFrequency: EmailFrequency;
  /** Per-category opt-in/out settings. */
  categoryPreferences: CategoryPreference[];
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating or fully replacing preferences.
 */
export interface UpdatePreferencesInput {
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  categoryPreferences?: CategoryPreference[];
}

/**
 * All known notification categories — used to build defaults.
 */
export const ALL_NOTIFICATION_TYPES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_update',
  'system_alert',
];

/**
 * Build the default preferences (everything enabled, instant delivery).
 */
export function buildDefaultPreferences(userId: string, id: string): UserPreferences {
  const now = new Date();
  return {
    id,
    userId,
    emailEnabled: true,
    emailFrequency: 'instant',
    categoryPreferences: ALL_NOTIFICATION_TYPES.map((category) => ({
      category,
      enabled: true,
    })),
    createdAt: now,
    updatedAt: now,
  };
}

parameters.new_string:
/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across
 * multiple channels (email, SMS, webhook). Per-channel settings
 * allow independent enable/disable per delivery channel, while
 * category preferences control which notification types are sent.
 */

import type { NotificationChannel, NotificationType } from './notification.js';

/**
 * How often a user wants to receive email notifications.
 * - instant: deliver immediately
 * - daily_digest: batch into a daily summary
 * - weekly_digest: batch into a weekly summary
 *
 * Note: only 'instant' is currently implemented. Digest modes
 * are modeled for forward-compatibility but not yet delivered.
 * Only applicable to email channel.
 */
export type EmailFrequency = 'instant' | 'daily_digest' | 'weekly_digest';

/**
 * Per-channel notification settings.
 */
export interface ChannelPreference {
  /** Whether this channel is enabled. */
  enabled: boolean;
  /** Delivery frequency — only meaningful for email. */
  frequency?: EmailFrequency;
}

/**
 * Per-category subscription setting.
 */
export interface CategoryPreference {
  /** The notification category. */
  category: NotificationType;
  /** Whether the user wants to receive this category. */
  enabled: boolean;
}

/**
 * Full notification preferences for a single user.
 */
export interface UserPreferences {
  /** Unique preferences record ID. */
  id: string;
  /** The user this preferences record belongs to. */
  userId: string;
  /** @deprecated Use channelPreferences.email.enabled instead. Kept for backward compatibility. */
  emailEnabled: boolean;
  /** @deprecated Use channelPreferences.email.frequency instead. Kept for backward compatibility. */
  emailFrequency: EmailFrequency;
  /** Per-channel enable/disable and settings. */
  channelPreferences: Partial<Record<NotificationChannel, ChannelPreference>>;
  /** Per-category opt-in/out settings (applies across all channels). */
  categoryPreferences: CategoryPreference[];
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating or updating preferences.
 */
export interface UpdatePreferencesInput {
  /** @deprecated Use channelPreferences instead. Still works for backward compatibility. */
  emailEnabled?: boolean;
  /** @deprecated Use channelPreferences instead. Still works for backward compatibility. */
  emailFrequency?: EmailFrequency;
  /** Per-channel settings to update. */
  channelPreferences?: Partial<Record<NotificationChannel, Partial<ChannelPreference>>>;
  categoryPreferences?: CategoryPreference[];
}

/**
 * All known notification categories — used to build defaults.
 */
export const ALL_NOTIFICATION_TYPES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_update',
  'system_alert',
];

/**
 * Default channel preferences — all channels enabled, email at instant frequency.
 */
export function buildDefaultChannelPreferences(): Partial<Record<NotificationChannel, ChannelPreference>> {
  return {
    email: { enabled: true, frequency: 'instant' },
    sms: { enabled: true },
    webhook: { enabled: true },
  };
}

/**
 * Build the default preferences (everything enabled, instant delivery, all channels on).
 */
export function buildDefaultPreferences(userId: string, id: string): UserPreferences {
  const now = new Date();
  const channelPrefs = buildDefaultChannelPreferences();
  return {
    id,
    userId,
    emailEnabled: true,
    emailFrequency: 'instant',
    channelPreferences: channelPrefs,
    categoryPreferences: ALL_NOTIFICATION_TYPES.map((category) => ({
      category,
      enabled: true,
    })),
    createdAt: now,
    updatedAt: now,
  };
}

