/**
 * Update preferences for a user. Creates the record if it doesn't exist yet.
 */
updatePreferences(userId: string, input: UpdatePreferencesInput): UserPreferences {
  this.logger.info(`Updating preferences for user ${userId}`);

  const existing = this.repository.findByUserId(userId);

  if (existing) {
    const updated: UserPreferences = {
      ...existing,
      ...(input.emailEnabled !== undefined && { emailEnabled: input.emailEnabled }),
      ...(input.emailFrequency !== undefined && { emailFrequency: input.emailFrequency }),
      ...(input.categoryPreferences !== undefined && { categoryPreferences: input.categoryPreferences }),
      updatedAt: new Date(),
    };
    return this.repository.update(existing.id, updated);
  }

  // Create new preferences based on defaults, then apply input
  const id = generatePreferencesId();
  const defaults = buildDefaultPreferences(userId, id);
  const newPrefs: UserPreferences = {
    ...defaults,
    ...(input.emailEnabled !== undefined && { emailEnabled: input.emailEnabled }),
    ...(input.emailFrequency !== undefined && { emailFrequency: input.emailFrequency }),
    ...(input.categoryPreferences !== undefined && { categoryPreferences: input.categoryPreferences }),
  };
  return this.repository.save(newPrefs);
}

parameters.new_string:
/**
 * Update preferences for a user. Creates the record if it doesn't exist yet.
 * Handles both legacy (emailEnabled/emailFrequency) and new (channelPreferences) inputs,
 * keeping them in sync.
 */
updatePreferences(userId: string, input: UpdatePreferencesInput): UserPreferences {
  this.logger.info(`Updating preferences for user ${userId}`);

  const existing = this.repository.findByUserId(userId);
  const base = existing ?? buildDefaultPreferences(userId, generatePreferencesId());

  const updated: UserPreferences = {
    ...base,
    ...(input.categoryPreferences !== undefined && { categoryPreferences: input.categoryPreferences }),
    updatedAt: new Date(),
  };

  // Merge channelPreferences if provided
  if (input.channelPreferences) {
    const merged = { ...updated.channelPreferences };
    for (const [ch, pref] of Object.entries(input.channelPreferences)) {
      if (pref) {
        merged[ch as NotificationChannel] = { ...merged[ch as NotificationChannel], ...pref };
      }
    }
    updated.channelPreferences = merged;
  }

  // Legacy field support: sync emailEnabled/emailFrequency with channelPreferences.email
  if (input.emailEnabled !== undefined) {
    updated.emailEnabled = input.emailEnabled;
    const emailPref = updated.channelPreferences.email ?? { enabled: true };
    updated.channelPreferences = {
      ...updated.channelPreferences,
      email: { ...emailPref, enabled: input.emailEnabled },
    };
  }
  if (input.emailFrequency !== undefined) {
    updated.emailFrequency = input.emailFrequency;
    const emailPref = updated.channelPreferences.email ?? { enabled: true };
    updated.channelPreferences = {
      ...updated.channelPreferences,
      email: { ...emailPref, frequency: input.emailFrequency },
    };
  }

  // If channelPreferences.email was updated directly, sync legacy fields
  if (input.channelPreferences?.email) {
    const emailPref = updated.channelPreferences.email;
    if (emailPref) {
      if (emailPref.enabled !== undefined) {
        updated.emailEnabled = emailPref.enabled;
      }
      if (emailPref.frequency !== undefined) {
        updated.emailFrequency = emailPref.frequency;
      }
    }
  }

  if (existing) {
    return this.repository.update(existing.id, updated);
  }
  return this.repository.save(updated);
}

