/**
 * Check whether a notification should be sent to a user based on their preferences.
 *
 * Returns true if:
 * 1. Email is globally enabled for the user
 * 2. The specific notification category is enabled
 *
 * Users without explicit preferences get defaults (all enabled).
 */
shouldSendNotification(userId: string, type: NotificationType): boolean {
  const prefs = this.getPreferences(userId);

  if (!prefs.emailEnabled) {
    this.logger.info(`Email disabled for user ${userId}, suppressing ${type}`);
    return false;
  }

  const catPref = prefs.categoryPreferences.find((cp) => cp.category === type);
  // If no category preference found, allow by default
  if (catPref && !catPref.enabled) {
    this.logger.info(`Category ${type} disabled for user ${userId}, suppressing`);
    return false;
  }

  return true;
}

parameters.new_string:
/**
 * Check whether a notification should be sent to a user based on their preferences.
 *
 * Returns true if:
 * 1. The channel is enabled for the user
 * 2. The specific notification category is enabled
 *
 * Users without explicit preferences get defaults (all enabled).
 *
 * @param channel - defaults to 'email' for backward compatibility
 */
shouldSendNotification(userId: string, type: NotificationType, channel: NotificationChannel = 'email'): boolean {
  const prefs = this.getPreferences(userId);

  // Check channel-level preference
  const channelPref = prefs.channelPreferences[channel];
  if (channelPref && !channelPref.enabled) {
    this.logger.info(`Channel ${channel} disabled for user ${userId}, suppressing ${type}`);
    return false;
  }

  // Backward compat: if no channelPreferences entry exists for email, fall back to legacy field
  if (channel === 'email' && !channelPref && !prefs.emailEnabled) {
    this.logger.info(`Email disabled for user ${userId}, suppressing ${type}`);
    return false;
  }

  // Check category-level preference
  const catPref = prefs.categoryPreferences.find((cp) => cp.category === type);
  if (catPref && !catPref.enabled) {
    this.logger.info(`Category ${type} disabled for user ${userId}, suppressing`);
    return false;
  }

  return true;
}

