    it('should update SMS channel preferences via channelPreferences', () => {
      const prefs = service.updatePreferences('user-1', {
        channelPreferences: { sms: { enabled: false } },
      });

      expect(prefs.channelPreferences.sms?.enabled).toBe(false);
      // Email should remain enabled
      expect(prefs.channelPreferences.email?.enabled).toBe(true);
    });

    it('should update webhook channel preferences via channelPreferences', () => {
      const prefs = service.updatePreferences('user-1', {
        channelPreferences: { webhook: { enabled: false } },
      });

      expect(prefs.channelPreferences.webhook?.enabled).toBe(false);
      expect(prefs.channelPreferences.email?.enabled).toBe(true);
      expect(prefs.channelPreferences.sms?.enabled).toBe(true);
    });

    it('should sync legacy fields when channelPreferences.email is updated', () => {
      const prefs = service.updatePreferences('user-1', {
        channelPreferences: { email: { enabled: false, frequency: 'weekly_digest' } },
      });

      expect(prefs.emailEnabled).toBe(false);
      expect(prefs.emailFrequency).toBe('weekly_digest');
      expect(prefs.channelPreferences.email?.enabled).toBe(false);
      expect(prefs.channelPreferences.email?.frequency).toBe('weekly_digest');
    });

    it('should update multiple channels at once', () => {
      const prefs = service.updatePreferences('user-1', {
        channelPreferences: {
          email: { enabled: true },
          sms: { enabled: false },
          webhook: { enabled: false },
        },
      });

      expect(prefs.channelPreferences.email?.enabled).toBe(true);
      expect(prefs.channelPreferences.sms?.enabled).toBe(false);
      expect(prefs.channelPreferences.webhook?.enabled).toBe(false);
    });
  });

  describe('shouldSendNotification', () => {
    it('should allow notification when all preferences are default', () => {
      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
    });

    it('should block notification when email is globally disabled', () => {
      service.updatePreferences('user-1', { emailEnabled: false });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'system_alert')).toBe(false);
    });

    it('should block notification for a disabled category', () => {
      const categories: CategoryPreference[] = ALL_NOTIFICATION_TYPES.map((cat) => ({
        category: cat,
        enabled: cat !== 'welcome',
      }));

      service.updatePreferences('user-1', { categoryPreferences: categories });

      expect(service.shouldSendNotification('user-1', 'welcome')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
    });

    it('should allow notification when email enabled and category enabled', () => {
      service.updatePreferences('user-1', { emailEnabled: true });

      expect(service.shouldSendNotification('user-1', 'order_status_update')).toBe(true);
    });

    it('should allow notification for unknown categories by default', () => {
      // If a category pref is missing for a type, default to allowed
      service.updatePreferences('user-1', { categoryPreferences: [] });

      expect(service.shouldSendNotification('user-1', 'system_alert')).toBe(true);
    });

    it('should default to email channel when channel is not specified', () => {
      service.updatePreferences('user-1', { emailEnabled: false });

      // Without channel param, defaults to email
      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(false);
    });

    it('should check SMS channel preferences independently', () => {
      service.updatePreferences('user-1', {
        channelPreferences: { sms: { enabled: false } },
      });

      // SMS disabled, email still enabled
      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'sms')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'email')).toBe(true);
    });

    it('should check webhook channel preferences independently', () => {
      service.updatePreferences('user-1', {
        channelPreferences: { webhook: { enabled: false } },
      });

      expect(service.shouldSendNotification('user-1', 'system_alert', 'webhook')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'system_alert', 'email')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'system_alert', 'sms')).toBe(true);
    });

    it('should block disabled category across all channels', () => {
      const categories: CategoryPreference[] = ALL_NOTIFICATION_TYPES.map((cat) => ({
        category: cat,
        enabled: cat !== 'welcome',
      }));
      service.updatePreferences('user-1', { categoryPreferences: categories });

      expect(service.shouldSendNotification('user-1', 'welcome', 'email')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'welcome', 'sms')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'welcome', 'webhook')).toBe(false);
    });

    it('should allow all channels when all are enabled', () => {
      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'email')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'sms')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'webhook')).toBe(true);
    });

    it('should allow selective channel disable — email off, sms on', () => {
      service.updatePreferences('user-1', {
        channelPreferences: {
          email: { enabled: false },
          sms: { enabled: true },
        },
      });

      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'email')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'sms')).toBe(true);
    });
  });

  describe('resetPreferences', () => {
    it('should reset to defaults after customization', () => {
      service.updatePreferences('user-1', {
        emailEnabled: false,
        emailFrequency: 'weekly_digest',
        channelPreferences: { sms: { enabled: false } },
      });

      const prefs = service.resetPreferences('user-1');

      expect(prefs.emailEnabled).toBe(true);
      expect(prefs.emailFrequency).toBe('instant');
      expect(prefs.channelPreferences.email?.enabled).toBe(true);
      expect(prefs.channelPreferences.sms?.enabled).toBe(true);
      expect(prefs.channelPreferences.webhook?.enabled).toBe(true);
    });

    it('should work for user with no saved preferences', () => {
      const prefs = service.resetPreferences('user-1');

      expect(prefs.emailEnabled).toBe(true);
      expect(prefs.emailFrequency).toBe('instant');
      expect(prefs.channelPreferences.email?.enabled).toBe(true);
    });
  });
});

