parameters.new_string:
  describe('adapter routing', () => {
    it('should work without adapters (fallback to in-memory)', async () => {
      const serviceNoAdapters = new NotificationService(eventBus);

      await serviceNoAdapters.sendNotification({
        type: 'system_alert',
        recipient: 'admin@example.com',
        subject: 'Test',
        body: 'Test body',
        channel: 'email',
      });

      expect(serviceNoAdapters.getNotificationCount()).toBe(1);
    });
  });

  describe('multi-channel preference checking', () => {
    let db: Database;
    let preferencesService: PreferencesService;
    let smsAdapter: SmsNotificationAdapter;
    let webhookAdapter: WebhookNotificationAdapter;
    let multiChannelService: NotificationService;

    beforeEach(() => {
      db = new Database();
      const prefRepo = new PreferencesRepository(db);
      preferencesService = new PreferencesService(prefRepo);
      resetPreferencesIdCounter();

      smsAdapter = new SmsNotificationAdapter({ fromNumber: '+15551234567' });
      webhookAdapter = new WebhookNotificationAdapter({ url: 'https://hooks.example.com/notify' });
      multiChannelService = new NotificationService(
        eventBus,
        [emailAdapter, smsAdapter, webhookAdapter],
        preferencesService,
      );
    });

    it('should send to all channels when all are enabled', async () => {
      await multiChannelService.sendNotification({
        type: 'system_alert',
        userId: 'user-1',
        recipient: 'alice@example.com',
        subject: 'Alert',
        body: 'System alert',
        channel: 'email',
      });
      await multiChannelService.sendNotification({
        type: 'system_alert',
        userId: 'user-1',
        recipient: '+15559876543',
        subject: 'Alert',
        body: 'System alert',
        channel: 'sms',
      });
      await multiChannelService.sendNotification({
        type: 'system_alert',
        userId: 'user-1',
        recipient: 'https://hooks.example.com/notify',
        subject: 'Alert',
        body: 'System alert',
        channel: 'webhook',
      });

      expect(multiChannelService.getNotificationCount()).toBe(3);
    });

    it('should suppress SMS when SMS channel is disabled', async () => {
      preferencesService.updatePreferences('user-1', {
        channelPreferences: { sms: { enabled: false } },
      });

      const emailResult = await multiChannelService.sendNotification({
        type: 'order_confirmation',
        userId: 'user-1',
        recipient: 'alice@example.com',
        subject: 'Order',
        body: 'Your order',
        channel: 'email',
      });
      const smsResult = await multiChannelService.sendNotification({
        type: 'order_confirmation',
        userId: 'user-1',
        recipient: '+15559876543',
        subject: 'Order',
        body: 'Your order',
        channel: 'sms',
      });

      expect(emailResult).not.toBeNull();
      expect(smsResult).toBeNull();
      expect(multiChannelService.getNotificationCount()).toBe(1);
    });

    it('should suppress email but allow SMS and webhook', async () => {
      preferencesService.updatePreferences('user-1', {
        channelPreferences: { email: { enabled: false } },
      });

      const emailResult = await multiChannelService.sendNotification({
        type: 'system_alert',
        userId: 'user-1',
        recipient: 'alice@example.com',
        subject: 'Alert',
        body: 'Alert body',
        channel: 'email',
      });
      const smsResult = await multiChannelService.sendNotification({
        type: 'system_alert',
        userId: 'user-1',
        recipient: '+15559876543',
        subject: 'Alert',
        body: 'Alert body',
        channel: 'sms',
      });
      const webhookResult = await multiChannelService.sendNotification({
        type: 'system_alert',
        userId: 'user-1',
        recipient: 'https://hooks.example.com/notify',
        subject: 'Alert',
        body: 'Alert body',
        channel: 'webhook',
      });

      expect(emailResult).toBeNull();
      expect(smsResult).not.toBeNull();
      expect(webhookResult).not.toBeNull();
    });

    it('should suppress disabled category across all channels', async () => {
      preferencesService.updatePreferences('user-1', {
        categoryPreferences: [
          { category: 'order_confirmation', enabled: true },
          { category: 'order_status_update', enabled: true },
          { category: 'welcome', enabled: false },
          { category: 'account_update', enabled: true },
          { category: 'system_alert', enabled: true },
        ],
      });

      const emailResult = await multiChannelService.sendNotification({
        type: 'welcome',
        userId: 'user-1',
        recipient: 'alice@example.com',
        subject: 'Welcome',
        body: 'Welcome!',
        channel: 'email',
      });
      const smsResult = await multiChannelService.sendNotification({
        type: 'welcome',
        userId: 'user-1',
        recipient: '+15559876543',
        subject: 'Welcome',
        body: 'Welcome!',
        channel: 'sms',
      });

      expect(emailResult).toBeNull();
      expect(smsResult).toBeNull();
    });

    it('should not check preferences when userId is not provided', async () => {
      preferencesService.updatePreferences('user-1', {
        channelPreferences: { email: { enabled: false }, sms: { enabled: false } },
      });

      // No userId — preferences are not checked
      const result = await multiChannelService.sendNotification({
        type: 'system_alert',
        recipient: 'admin@example.com',
        subject: 'Alert',
        body: 'System alert',
        channel: 'email',
      });

      expect(result).not.toBeNull();
    });
  });
});

